     1→'use client';
     2→
     3→// ============================================================================
     4→// ARCHIVE VIEW
     5→// Unified view for browsing all saved materials (tools, PDFs, photos)
     6→// Issue #37: Unified Archive page with bookmark, rating, filters
     7→// ============================================================================
     8→
     9→import { useState, useEffect, useMemo, useCallback, type ChangeEvent } from 'react';
    10→import { AnimatePresence } from 'framer-motion';
    11→import {
    12→  Grid,
    13→  List,
    14→  Search,
    15→  Calendar,
    16→  ArrowUpDown,
    17→  X,
    18→  BookOpen,
    19→  Filter,
    20→} from 'lucide-react';
    21→import { Button } from '@/components/ui/button';
    22→import { cn } from '@/lib/utils';
    23→import { logger } from '@/lib/logger';
    24→import {
    25→  getActiveMaterials,
    26→  deleteMaterial,
    27→} from '@/lib/storage/materials-db';
    28→
    29→// Import extracted components
    30→import {
    31→  type FilterType,
    32→  type SortBy,
    33→  type ViewMode,
    34→  type ArchiveItem,
    35→  SORT_OPTIONS,
    36→  FILTER_TABS,
    37→  TOOL_LABELS,
    38→  SUBJECT_LABELS,
    39→  updateMaterialInteraction,
    40→  EmptyState,
    41→  GridView,
    42→  ListView,
    43→  MaterialViewer,
    44→} from './archive';
    45→
    46→// ============================================================================
    47→// Main Component
    48→// ============================================================================
    49→
    50→export function ArchiveView() {
    51→  const [filter, setFilter] = useState<FilterType>('all');
    52→  const [sortBy, setSortBy] = useState<SortBy>('date');
    53→  const [searchQuery, setSearchQuery] = useState('');
    54→  const [viewMode, setViewMode] = useState<ViewMode>('grid');
    55→  const [materials, setMaterials] = useState<ArchiveItem[]>([]);
    56→  const [isLoading, setIsLoading] = useState(true);
    57→  const [selectedItem, setSelectedItem] = useState<ArchiveItem | null>(null);
    58→  // Subject filter (Issue #37)
    59→  const [subjectFilter, setSubjectFilter] = useState<string>('all');
    60→  // Date range filter (Issue #37)
    61→  const [dateFrom, setDateFrom] = useState<string>('');
    62→  const [dateTo, setDateTo] = useState<string>('');
    63→
    64→  // Load materials from IndexedDB
    65→  useEffect(() => {
    66→    async function loadMaterials() {
    67→      try {
    68→        setIsLoading(true);
    69→        const records = await getActiveMaterials();
    70→        setMaterials(records as ArchiveItem[]);
    71→      } catch (error) {
    72→        logger.error('Failed to load materials', { error });
    73→      } finally {
    74→        setIsLoading(false);
    75→      }
    76→    }
    77→    loadMaterials();
    78→  }, []);
    79→
    80→  // Extract unique subjects from materials
    81→  const availableSubjects = useMemo(() => {
    82→    const subjects = new Set<string>();
    83→    for (const item of materials) {
    84→      if (item.subject) {
    85→        subjects.add(item.subject);
    86→      }
    87→    }
    88→    return Array.from(subjects).sort();
    89→  }, [materials]);
    90→
    91→  // Filter and sort materials
    92→  const filtered = useMemo(() => {
    93→    let result = [...materials];
    94→
    95→    // Filter by type or bookmarked
    96→    if (filter === 'bookmarked') {
    97→      result = result.filter((item) => item.isBookmarked);
    98→    } else if (filter !== 'all') {
    99→      result = result.filter((item) => item.toolType === filter);
   100→    }
   101→
   102→    // Filter by subject (Issue #37)
   103→    if (subjectFilter !== 'all') {
   104→      result = result.filter((item) => item.subject === subjectFilter);
   105→    }
   106→
   107→    // Filter by date range (Issue #37)
   108→    if (dateFrom) {
   109→      const fromDate = new Date(dateFrom);
   110→      fromDate.setHours(0, 0, 0, 0);
   111→      result = result.filter((item) => new Date(item.createdAt) >= fromDate);
   112→    }
   113→    if (dateTo) {
   114→      const toDate = new Date(dateTo);
   115→      toDate.setHours(23, 59, 59, 999);
   116→      result = result.filter((item) => new Date(item.createdAt) <= toDate);
   117→    }
   118→
   119→    // Filter by search query
   120→    if (searchQuery.trim()) {
   121→      const query = searchQuery.toLowerCase();
   122→      result = result.filter(
   123→        (item) =>
   124→          item.title?.toLowerCase().includes(query) ||
   125→          item.maestroId?.toLowerCase().includes(query) ||
   126→          item.toolType.toLowerCase().includes(query) ||
   127→          item.subject?.toLowerCase().includes(query)
   128→      );
   129→    }
   130→
   131→    // Sort
   132→    result.sort((a, b) => {
   133→      switch (sortBy) {
   134→        case 'date':
   135→          return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
   136→        case 'type':
   137→          return a.toolType.localeCompare(b.toolType);
   138→        case 'rating':
   139→          return (b.userRating || 0) - (a.userRating || 0);
   140→        case 'views':
   141→          return (b.viewCount || 0) - (a.viewCount || 0);
   142→        default:
   143→          return 0;
   144→      }
   145→    });
   146→
   147→    return result;
   148→  }, [materials, filter, searchQuery, sortBy, subjectFilter, dateFrom, dateTo]);
   149→
   150→  // Handlers
   151→  const handleDelete = async (toolId: string) => {
   152→    if (!confirm('Sei sicuro di voler eliminare questo materiale?')) return;
   153→
   154→    try {
   155→      await deleteMaterial(toolId);
   156→      setMaterials((prev) => prev.filter((m) => m.toolId !== toolId));
   157→    } catch (error) {
   158→      logger.error('Failed to delete material', { error });
   159→    }
   160→  };
   161→
   162→  const handleView = useCallback((item: ArchiveItem) => {
   163→    logger.debug('Opening material viewer', { toolId: item.toolId, toolType: item.toolType });
   164→    setSelectedItem(item);
   165→  }, []);
   166→
   167→  const handleCloseViewer = useCallback(() => {
   168→    setSelectedItem(null);
   169→  }, []);
   170→
   171→  const handleSearchChange = (e: ChangeEvent<HTMLInputElement>) => {
   172→    setSearchQuery(e.target.value);
   173→  };
   174→
   175→  // Bookmark handler
   176→  const handleBookmark = useCallback(async (toolId: string, isBookmarked: boolean) => {
   177→    const success = await updateMaterialInteraction(toolId, { isBookmarked });
   178→    if (success) {
   179→      setMaterials((prev) =>
   180→        prev.map((m) => (m.toolId === toolId ? { ...m, isBookmarked } : m))
   181→      );
   182→    }
   183→  }, []);
   184→
   185→  // Rating handler
   186→  const handleRate = useCallback(async (toolId: string, userRating: number) => {
   187→    const success = await updateMaterialInteraction(toolId, { userRating });
   188→    if (success) {
   189→      setMaterials((prev) =>
   190→        prev.map((m) => (m.toolId === toolId ? { ...m, userRating } : m))
   191→      );
   192→    }
   193→  }, []);
   194→
   195→  // Count by type for tab badges
   196→  const countByType = useMemo(() => {
   197→    const counts: Record<string, number> = {
   198→      all: materials.length,
   199→      bookmarked: materials.filter((m) => m.isBookmarked).length,
   200→    };
   201→    for (const item of materials) {
   202→      counts[item.toolType] = (counts[item.toolType] || 0) + 1;
   203→    }
   204→    return counts;
   205→  }, [materials]);
   206→
   207→  return (
   208→    <div className="space-y-6">
   209→      {/* Header */}
   210→      <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center justify-between">
   211→        <div>
   212→          <h1 className="text-2xl font-bold text-slate-900 dark:text-white">
   213→            Archivio
   214→          </h1>
   215→          <p className="text-sm text-slate-500 dark:text-slate-400">
