     2→// MATERIALS DATABASE
     3→// IndexedDB storage for uploaded files (webcam photos, PDFs)
     4→// Uses the idb library for a Promise-based IndexedDB API
     5→// Issue #22: Materials Archive - Storage (IndexedDB)
     6→// ============================================================================
     7→
     8→import { openDB, DBSchema, IDBPDatabase } from 'idb';
     9→import { logger } from '@/lib/logger';
    10→import type { ToolType } from '@/types/tools';
    11→
    12→// ============================================================================
    13→// DATABASE SCHEMA
    14→// ============================================================================
    15→
    16→interface MaterialsDB extends DBSchema {
    17→  files: {
    18→    key: string;
    19→    value: {
    20→      id: string;
    21→      blob: Blob;
    22→      thumbnail?: Blob;
    23→      createdAt: number;
    24→    };
    25→  };
    26→  metadata: {
    27→    key: string;
    28→    value: {
    29→      id: string;
    30→      filename: string;
    31→      format: 'image' | 'pdf';
    32→      mimeType: string;
    33→      subject?: string;
    34→      maestroId?: string;
    35→      size: number;
    36→      pageCount?: number;
    37→      createdAt: Date;
    38→      updatedAt: Date;
    39→    };
    40→    indexes: {
    41→      'by-date': Date;
    42→      'by-subject': string;
    43→      'by-format': string;
    44→    };
    45→  };
    46→}
    47→
