   850→    name: 'set_learning_differences',
   851→    description:
   852→      'Imposta le difficoltà di apprendimento. Usa quando lo studente menziona dislessia, ADHD, autismo, etc.',
   853→    parameters: {
   854→      type: 'object',
   855→      properties: {
   856→        differences: {
   857→          type: 'array',
   858→          items: {
   859→            type: 'string',
   860→            enum: [
   861→              'dyslexia',
   862→              'dyscalculia',
   863→              'dysgraphia',
   864→              'adhd',
   865→              'autism',
   866→              'cerebralPalsy',
   867→              'visualImpairment',
   868→              'auditoryProcessing',
   869→            ],
   870→          },
   871→          description: 'Lista delle difficoltà di apprendimento',
   872→        },
   873→      },
   874→      required: ['differences'],
   875→    },
   876→  },
   877→  {
   878→    type: 'function',
   879→    name: 'set_student_gender',
   880→    description:
   881→      'Imposta il genere dello studente per personalizzare il buddy. Usa quando lo studente indica la preferenza.',
   882→    parameters: {
   883→      type: 'object',
   884→      properties: {
   885→        gender: {
   886→          type: 'string',
   887→          enum: ['male', 'female', 'other'],
   888→          description: 'Genere dello studente',
   889→        },
   890→      },
   891→      required: ['gender'],
   892→    },
   893→  },
   894→  {
   895→    type: 'function',
   896→    name: 'confirm_step_data',
   897→    description:
   898→      'Conferma i dati raccolti e chiedi allo studente se sono corretti. Usa dopo aver raccolto le informazioni principali.',
   899→    parameters: {
   900→      type: 'object',
   901→      properties: {},
   902→      required: [],
   903→    },
   904→  },
   905→  {
   906→    type: 'function',
   907→    name: 'next_onboarding_step',
   908→    description:
   909→      "Avanza al prossimo step dell'onboarding. Usa quando lo studente è pronto a continuare.",
   910→    parameters: {
   911→      type: 'object',
   912→      properties: {},
   913→      required: [],
   914→    },
   915→  },
   916→  {
   917→    type: 'function',
   918→    name: 'prev_onboarding_step',
   919→    description:
   920→      'Torna allo step precedente. Usa quando lo studente vuole modificare qualcosa.',
   921→    parameters: {
