   928→
   929→// ============================================================================
   930→// MINDMAP MODIFICATION COMMAND HELPERS
   931→// ============================================================================
   932→
   933→/**
   934→ * List of mindmap modification command names.
   935→ */
   936→const MINDMAP_MODIFICATION_COMMANDS = [
   937→  'mindmap_add_node',
   938→  'mindmap_connect_nodes',
   939→  'mindmap_expand_node',
   940→  'mindmap_delete_node',
   941→  'mindmap_focus_node',
   942→  'mindmap_set_color',
   943→] as const;
   944→
   945→/**
   946→ * Check if a tool name is a mindmap modification command.
   947→ */
   948→export function isMindmapModificationCommand(name: string): boolean {
   949→  return MINDMAP_MODIFICATION_COMMANDS.includes(name as typeof MINDMAP_MODIFICATION_COMMANDS[number]);
   950→}
   951→
   952→// ============================================================================
   953→// SUMMARY MODIFICATION COMMAND HELPERS (#70 Real-time Summary Tool)
   954→// ============================================================================
   955→
   956→/**
   957→ * List of summary modification command names.
   958→ */
   959→const SUMMARY_MODIFICATION_COMMANDS = [
   960→  'summary_set_title',
   961→  'summary_add_section',
   962→  'summary_add_point',
   963→  'summary_finalize',
   964→  'student_summary_add_comment', // #70 maieutic method
   965→] as const;
   966→
   967→/**
   968→ * Check if a tool name is a summary modification command.
   969→ */
   970→export function isSummaryModificationCommand(name: string): boolean {
   971→  return SUMMARY_MODIFICATION_COMMANDS.includes(name as typeof SUMMARY_MODIFICATION_COMMANDS[number]);
   972→}
   973→
   974→// ============================================================================
   975→// ONBOARDING COMMAND HELPERS (#61 Onboarding Voice Integration)
   976→// ============================================================================
   977→
   978→/**
   979→ * List of onboarding command names.
   980→ */
   981→const ONBOARDING_COMMANDS = [
   982→  'set_student_name',
   983→  'set_student_age',
   984→  'set_school_level',
   985→  'set_learning_differences',
   986→  'set_student_gender',
   987→  'confirm_step_data',
   988→  'next_onboarding_step',
   989→  'prev_onboarding_step',
   990→] as const;
   991→
   992→/**
   993→ * Check if a tool name is an onboarding command.
   994→ */
   995→export function isOnboardingCommand(name: string): boolean {
   996→  return ONBOARDING_COMMANDS.includes(name as typeof ONBOARDING_COMMANDS[number]);
   997→}
   998→
   999→// ============================================================================
  1000→// TOOL NAME TO TYPE MAPPING
  1001→// ============================================================================
  1002→
  1003→/**
  1004→ * Maps voice tool names to ToolType.
  1005→ */
  1006→export function getToolTypeFromName(name: string): ToolType | null {
  1007→  switch (name) {
  1008→    case 'create_mindmap':
  1009→      return 'mindmap';
  1010→    case 'create_quiz':
  1011→      return 'quiz';
  1012→    case 'create_flashcards':
  1013→      return 'flashcards';
  1014→    case 'create_summary':
  1015→    case 'open_student_summary': // #70 maieutic method
  1016→      return 'summary';
  1017→    case 'create_diagram':
  1018→      return 'diagram';
  1019→    case 'create_timeline':
  1020→      return 'timeline';
  1021→    case 'create_demo':
  1022→      return 'demo';
  1023→    default:
  1024→      return null;
  1025→  }
  1026→}
  1027→
  1028→/**
  1029→ * Check if a tool name is a tool creation command.
  1030→ */
  1031→export function isToolCreationCommand(name: string): boolean {
  1032→  return getToolTypeFromName(name) !== null;
  1033→}
  1034→
  1035→// ============================================================================
  1036→// TOOL EXECUTION API
  1037→// ============================================================================
  1038→
  1039→/**
  1040→ * Execute a voice tool command via the API.
  1041→ * This triggers the server-side tool creation and SSE broadcast.
  1042→ */
  1043→export async function executeVoiceTool(
  1044→  sessionId: string,
  1045→  maestroId: string,
  1046→  toolName: string,
  1047→  args: Record<string, unknown>
  1048→): Promise<VoiceToolCallResult> {
  1049→  // Check for mindmap modification commands first
  1050→  if (isMindmapModificationCommand(toolName)) {
  1051→    return executeMindmapModification(sessionId, toolName, args);
  1052→  }
  1053→
  1054→  // Check for summary modification commands (#70 Real-time Summary Tool)
  1055→  if (isSummaryModificationCommand(toolName)) {
  1056→    return executeSummaryModification(sessionId, toolName, args);
  1057→  }
  1058→
  1059→  // Check for onboarding commands (#61 Onboarding Voice Integration)
  1060→  if (isOnboardingCommand(toolName)) {
  1061→    return executeOnboardingTool(toolName, args);
  1062→  }
  1063→
  1064→  const toolType = getToolTypeFromName(toolName);
  1065→
  1066→  // Non-tool commands (web_search, capture_homework) are handled differently
  1067→  if (!toolType) {
  1068→    return { success: true, displayed: false };
  1069→  }
  1070→
  1071→  try {
  1072→    // Call the API to create the tool and broadcast events
  1073→    const response = await fetch('/api/tools/create', {
  1074→      method: 'POST',
  1075→      headers: { 'Content-Type': 'application/json' },
  1076→      body: JSON.stringify({
  1077→        sessionId,
  1078→        maestroId,
  1079→        toolType,
  1080→        title: args.title || args.name || 'Untitled',
  1081→        subject: args.subject,
  1082→        content: args,
  1083→      }),
  1084→    });
  1085→
  1086→    if (!response.ok) {
  1087→      const error = await response.json();
  1088→      return { success: false, error: error.message || 'Failed to create tool' };
  1089→    }
  1090→
  1091→    const result = await response.json();
  1092→    return {
  1093→      success: true,
  1094→      toolId: result.toolId,
  1095→      toolType,
  1096→      displayed: true,
  1097→    };
  1098→  } catch (error) {
  1099→    logger.error('[VoiceToolCommands] Failed to execute tool', { error });
  1100→    return {
  1101→      success: false,
  1102→      error: error instanceof Error ? error.message : 'Unknown error',
  1103→    };
  1104→  }
  1105→}
  1106→
  1107→/**
  1108→ * Execute a mindmap modification command via SSE broadcast.
  1109→ * These commands modify an existing mindmap in real-time.
  1110→ */
  1111→export async function executeMindmapModification(
  1112→  sessionId: string,
  1113→  commandName: string,
  1114→  args: Record<string, unknown>
  1115→): Promise<VoiceToolCallResult> {
  1116→  try {
  1117→    // Send modification event to SSE endpoint
  1118→    const response = await fetch('/api/tools/stream/modify', {
  1119→      method: 'POST',
  1120→      headers: { 'Content-Type': 'application/json' },
  1121→      body: JSON.stringify({
  1122→        sessionId,
  1123→        command: commandName,
  1124→        args,
  1125→      }),
  1126→    });
  1127→
  1128→    if (!response.ok) {
  1129→      const error = await response.json();
  1130→      return {
  1131→        success: false,
  1132→        error: error.message || 'Failed to modify mindmap',
  1133→      };
  1134→    }
  1135→
  1136→    logger.info('[VoiceToolCommands] Mindmap modification sent', { commandName, args });
  1137→    return {
  1138→      success: true,
  1139→      toolType: 'mindmap',
  1140→      displayed: true,
  1141→    };
  1142→  } catch (error) {
  1143→    logger.error('[VoiceToolCommands] Failed to modify mindmap', { error });
  1144→    return {
  1145→      success: false,
  1146→      error: error instanceof Error ? error.message : 'Unknown error',
  1147→    };
  1148→  }
  1149→}
  1150→
  1151→/**
  1152→ * Execute a summary modification command via SSE broadcast.
  1153→ * These commands modify an existing summary in real-time.
  1154→ */
  1155→export async function executeSummaryModification(
  1156→  sessionId: string,
  1157→  commandName: string,
  1158→  args: Record<string, unknown>
  1159→): Promise<VoiceToolCallResult> {
  1160→  try {
  1161→    // Send modification event to SSE endpoint
  1162→    const response = await fetch('/api/tools/stream/modify', {
  1163→      method: 'POST',
  1164→      headers: { 'Content-Type': 'application/json' },
  1165→      body: JSON.stringify({
  1166→        sessionId,
  1167→        toolType: 'summary',
  1168→        command: commandName,
  1169→        args,
  1170→      }),
  1171→    });
  1172→
  1173→    if (!response.ok) {
  1174→      const error = await response.json();
  1175→      return {
  1176→        success: false,
  1177→        error: error.message || 'Failed to modify summary',
  1178→      };
  1179→    }
  1180→
  1181→    logger.info('[VoiceToolCommands] Summary modification sent', { commandName, args });
  1182→    return {
  1183→      success: true,
  1184→      toolType: 'summary',
  1185→      displayed: true,
  1186→    };
  1187→  } catch (error) {
  1188→    logger.error('[VoiceToolCommands] Failed to modify summary', { error });
  1189→    return {
  1190→      success: false,
  1191→      error: error instanceof Error ? error.message : 'Unknown error',
  1192→    };
  1193→  }
  1194→}
  1195→
  1196→/**
  1197→ * Generate a tool ID for a voice command.
  1198→ */
  1199→export function generateToolId(): string {
  1200→  return `voice-tool-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  1201→}
  1202→
  1203→// ============================================================================
  1204→// TOOL INSTRUCTION PROMPTS
  1205→// ============================================================================
  1206→
  1207→/**
  1208→ * Additional instructions for the AI about when to use tools.
  1209→ * Injected into the voice session instructions.
  1210→ */
  1211→export const TOOL_USAGE_INSTRUCTIONS = `
  1212→## STRUMENTI DISPONIBILI
  1213→
  1214→Hai accesso a strumenti per creare materiali didattici. USA questi strumenti quando appropriato:
  1215→
  1216→### Quando usare create_mindmap:
  1217→- Lo studente dice "fammi una mappa", "crea uno schema", "organizza questo argomento"
  1218→- Vuole vedere le connessioni tra concetti
  1219→- Chiede di visualizzare un argomento
  1220→
  1221→### Quando usare create_quiz:
  1222→- Lo studente dice "interrogami", "fammi delle domande", "voglio fare un test"
  1223→- Vuole verificare cosa ha capito
  1224→- Si sta preparando per una verifica
  1225→
  1226→**REGOLA IMPORTANTE PER I QUIZ:**
  1227→Prima di creare un quiz, CHIEDI SEMPRE allo studente: "Preferisci fare il quiz per iscritto, così lo vedi sullo schermo, oppure a voce così te lo faccio io?"
  1228→- Se sceglie **PER ISCRITTO**: usa create_quiz per mostrare le domande sullo schermo
  1229→- Se sceglie **A VOCE**: NON usare create_quiz! Fai tu le domande a voce:
  1230→  1. Leggi la domanda ad alta voce
  1231→  2. Elenca le opzioni (A, B, C, D)
  1232→  3. Aspetta la risposta dello studente
  1233→  4. Conferma se è corretta o spiega perché è sbagliata
  1234→  5. Passa alla domanda successiva
  1235→  6. Alla fine dai un resoconto del punteggio
  1236→
  1237→### Quando usare create_flashcards:
  1238→- Lo studente dice "fammi delle flashcard", "devo memorizzare"
  1239→- Vuole imparare vocaboli, date, formule, definizioni
  1240→- Chiede aiuto per memorizzare
  1241→
  1242→### Quando usare open_student_summary (PREFERITO - metodo maieutico):
  1243→- Lo studente dice "devo fare un riassunto", "devo scrivere un riassunto"
  1244→- Vuole scrivere LUI STESSO il riassunto (compito, esercizio)
  1245→- Apre l'editor vuoto, lo studente scrive, tu guidi con domande
  1246→
  1247→### Quando usare create_summary (solo se lo studente vuole che tu generi):
  1248→- Lo studente dice "riassumimi TU", "fai TU una sintesi"
  1249→- Ha bisogno di un ripasso veloce generato dall'AI
  1250→- Vuole i punti chiave senza scrivere lui stesso
  1251→
  1252→## COMANDI VOCALI PER RIASSUNTI DELLO STUDENTE (metodo maieutico)
  1253→
  1254→### student_summary_add_comment
  1255→- Usa per dare feedback sul testo scritto dallo studente
  1256→- Evidenzia parti specifiche e aggiungi commenti costruttivi
  1257→- Es: "Questo punto potrebbe essere più chiaro" oppure "Ottima osservazione!"
  1258→
  1259→## COMANDI VOCALI PER MODIFICARE RIASSUNTI (legacy)
  1260→
  1261→Quando c'è un riassunto attivo, lo studente può modificarlo vocalmente:
  1262→
  1263→### summary_set_title
  1264→- Imposta il titolo quando lo studente dice l'argomento
  1265→
  1266→### summary_add_section
  1267→- "Parliamo di [argomento]" - crea una nuova sezione
  1268→- "Aggiungi una sezione su [tema]" - nuova sezione
  1269→
  1270→### summary_add_point
  1271→- "Ricorda che..." - aggiunge un punto alla sezione corrente
  1272→- "Un altro punto importante è..." - aggiunge punto
  1273→
  1274→### summary_finalize
  1275→- "Ho finito" - salva e chiude il riassunto
  1276→- "Salva il riassunto" - finalizza
  1277→
  1278→### Quando usare create_diagram:
  1279→- Lo studente chiede un flowchart, un diagramma di flusso
  1280→- Vuole visualizzare un processo o algoritmo
  1281→- Ha bisogno di vedere relazioni (ER diagram)
  1282→
  1283→### Quando usare create_timeline:
  1284→- Lo studente studia storia e chiede una linea del tempo
  1285→- Vuole ordinare eventi cronologicamente
  1286→- Ha bisogno di visualizzare sequenze storiche
  1287→
  1288→### Quando usare capture_homework:
  1289→- Lo studente ha un esercizio scritto e ha bisogno di aiuto
  1290→- Dice "ti faccio vedere", "guarda questo problema"
  1291→- Ha difficoltà con un compito specifico
  1292→
  1293→## COMANDI VOCALI PER MODIFICARE MAPPE MENTALI
  1294→
  1295→Quando c'è una mappa mentale attiva, lo studente può modificarla vocalmente:
  1296→
  1297→### mindmap_add_node
  1298→- "Aggiungi [concetto]" - aggiunge un nuovo nodo
  1299→- "Metti anche [concetto]" - aggiunge un nodo collegato
  1300→- "Inserisci [concetto] sotto [nodo]" - aggiunge figlio specifico
  1301→
  1302→### mindmap_connect_nodes
  1303→- "Collega [A] con [B]" - crea connessione tra due nodi
  1304→- "Unisci [A] e [B]" - collega i nodi
  1305→
  1306→### mindmap_expand_node
  1307→- "Espandi [nodo]" - genera sotto-nodi automaticamente
  1308→- "Approfondisci [nodo]" - aggiunge dettagli
  1309→
  1310→### mindmap_delete_node
  1311→- "Cancella [nodo]" - rimuove il nodo
  1312→- "Togli [nodo]" - elimina dalla mappa
  1313→
  1314→### mindmap_focus_node
  1315→- "Vai a [nodo]" - centra la vista su quel nodo
  1316→- "Mostrami [nodo]" - zoom su nodo specifico
  1317→
  1318→### mindmap_set_color
  1319→- "Colora [nodo] di rosso/blu/verde" - cambia colore
  1320→- "Fai [nodo] giallo" - imposta colore
  1321→
  1322→NOTA: Quando crei uno strumento, ANNUNCIALO prima vocalmente (es. "Ti preparo un quiz su questo argomento...") e poi invoca la funzione.
  1323→`;
