/**
 * List of mindmap modification command names.
 */
const MINDMAP_MODIFICATION_COMMANDS = [
  'mindmap_add_node',
  'mindmap_connect_nodes',
  'mindmap_expand_node',
  'mindmap_delete_node',
  'mindmap_focus_node',
  'mindmap_set_color',
